CO-privileged-pod-namespace-share.script:
#!/usr/bin/env python3
# CO-privileged-pod-namespace-share: scan pod specs for privileged, hostPID/hostIPC/hostNetwork,
# hostPath mounts, and root containers. READ-ONLY static scan. Accepts stdin JSON, file arg, or sample.
import sys, json

SAMPLE = {"items":[{"metadata":{"name":"debug-pod","namespace":"default"},
  "spec":{"hostPID":True,"hostNetwork":True,
    "volumes":[{"name":"root","hostPath":{"path":"/"}}],
    "containers":[{"name":"c","securityContext":{"privileged":True}}]}},
  {"metadata":{"name":"web","namespace":"prod"},
  "spec":{"containers":[{"name":"c","securityContext":{"runAsNonRoot":True,"privileged":False}}]}}]}

def load():
    data = None
    if not sys.stdin.isatty():
        raw = sys.stdin.read().strip()
        if raw:
            try: data = json.loads(raw)
            except json.JSONDecodeError: data = None
    if data is None and len(sys.argv) > 1:
        try: data = json.load(open(sys.argv[1]))
        except (OSError, json.JSONDecodeError): data = None
    return data if data is not None else SAMPLE

d = load()
items = d.get('items', [d]) if isinstance(d, dict) else [d]
vuln = False
print('=== privileged / namespace-share pod scan ===')
for it in items:
    spec = it.get('spec', {}) or {}
    md = it.get('metadata', {}) or {}
    name = md.get('name','?'); ns = md.get('namespace','?')
    flags = []
    if spec.get('hostPID'): flags.append('hostPID')
    if spec.get('hostIPC'): flags.append('hostIPC')
    if spec.get('hostNetwork'): flags.append('hostNetwork')
    for v in spec.get('volumes', []) or []:
        if 'hostPath' in (v or {}): flags.append(f"hostPath:{v['hostPath'].get('path','?')}")
    for c in spec.get('containers', []) or []:
        sc = c.get('securityContext', {}) or {}
        if sc.get('privileged'): flags.append(f"privileged:{c.get('name')}")
        if sc.get('allowPrivilegeEscalation'): flags.append(f"allowPrivEsc:{c.get('name')}")
    if flags:
        vuln = True
        print(f'  {ns}/{name}: ' + ', '.join(flags))
        print('    VULNERABLE: pod shares host namespaces / runs privileged / mounts hostPath -> node takeover & cross-pod reach. Drop privileges, disable host namespaces, remove hostPath, enforce restricted PSS.')
    else:
        print(f'  {ns}/{name}: clean')
print('PASS' if not vuln else 'VULNERABLE (see pods above)')
sys.exit(2 if vuln else 0)

CO-sa-token-overmount.script:
#!/usr/bin/env python3
# CO-sa-token-overmount: flag pods/SAs that automount a SA token when unneeded
# and tokens with broad/default audiences. READ-ONLY static scan.
import sys, json

SAMPLE = {"items":[
  {"kind":"Pod","metadata":{"name":"frontend","namespace":"web"},
   "spec":{"serviceAccountName":"default","automountServiceAccountToken":True,
     "containers":[{"name":"c"}]}},
  {"kind":"Pod","metadata":{"name":"worker","namespace":"jobs"},
   "spec":{"serviceAccountName":"worker-sa","automountServiceAccountToken":False,
     "volumes":[{"name":"tok","projected":{"sources":[{"serviceAccountToken":{"audience":"vault","expirationSeconds":3600}}]}}],
     "containers":[{"name":"c"}]}}
]}

def load():
    if not sys.stdin.isatty():
        raw = sys.stdin.read().strip()
        if raw:
            try: return json.loads(raw)
            except json.JSONDecodeError: pass
    if len(sys.argv) > 1:
        try: return json.load(open(sys.argv[1]))
        except (OSError, json.JSONDecodeError): pass
    return SAMPLE

d = load()
items = d.get('items', [d]) if isinstance(d, dict) else [d]
vuln = False
print('=== SA token overmount audit ===')
for it in items:
    spec = it.get('spec', {}) or {}
    md = it.get('metadata', {}) or {}
    name = md.get('name','?'); ns = md.get('namespace','?')
    sa = spec.get('serviceAccountName', 'default')
    automount = spec.get('automountServiceAccountToken')
    # default behaviour is automount=True when unset
    mounts = (automount is True) or (automount is None)
    # projected token audiences
    auds = []
    for v in spec.get('volumes', []) or []:
        for s in (v.get('projected', {}) or {}).get('sources', []) or []:
            sat = s.get('serviceAccountToken')
            if sat: auds.append(sat.get('audience','<api-server-default>'))
    print(f'  {ns}/{name}: sa={sa} automount={automount} token_audiences={auds or "[default]"}')
    if mounts and sa == 'default':
        vuln = True
        print('    VULNERABLE: pod automounts the DEFAULT SA token unnecessarily -> a compromised container gets API creds. Set automountServiceAccountToken=false unless required; use a dedicated least-priv SA + scoped audience.')
    elif mounts and (not auds):
        print('    INFO: automounts an api-server-audience token; scope audience + short expiry if the API server is not needed.')
print('PASS' if not vuln else 'VULNERABLE (see pods above)')
sys.exit(2 if vuln else 0)

CO-untrusted-image-pull.script:
#!/usr/bin/env python3
# CO-untrusted-image-pull: flag mutable-tag images (no digest pin), missing imagePullPolicy,
# and absence of any signature/admission verification annotation. READ-ONLY static scan.
import sys, json, re

SAMPLE = {"items":[
  {"metadata":{"name":"api","namespace":"prod","annotations":{}},
   "spec":{"containers":[{"name":"c","image":"registry.example.test/api:latest"}]}},
  {"metadata":{"name":"db","namespace":"prod","annotations":{"cosign.sigstore.dev/verified":"true"}},
   "spec":{"containers":[{"name":"c","image":"registry.example.test/db@sha256:"+"a"*64,"imagePullPolicy":"IfNotPresent"}]}}
]}

def load():
    if not sys.stdin.isatty():
        raw = sys.stdin.read().strip()
        if raw:
            try: return json.loads(raw)
            except json.JSONDecodeError: pass
    if len(sys.argv) > 1:
        try: return json.load(open(sys.argv[1]))
        except (OSError, json.JSONDecodeError): pass
    return SAMPLE

d = load()
items = d.get('items', [d]) if isinstance(d, dict) else [d]
vuln = False
print('=== untrusted image-pull audit ===')
for it in items:
    md = it.get('metadata', {}) or {}
    ann = md.get('annotations', {}) or {}
    name = md.get('name','?'); ns = md.get('namespace','?')
    verified = any(k for k in ann if re.search(r'cosign|sigstore|notary|verified|kyverno|connaisseur', k, re.I))
    for c in (it.get('spec', {}) or {}).get('containers', []) or []:
        img = c.get('image','')
        pinned = '@sha256:' in img
        tag_latest = img.endswith(':latest') or (':' not in img.split('/')[-1])
        print(f'  {ns}/{name} [{img}]: digest_pinned={pinned} signature_verified={verified}')
        if not pinned and (tag_latest or not verified):
            vuln = True
            print('    VULNERABLE: image referenced by mutable tag with no digest pin and no signature/admission verification -> a poisoned registry/tag is pulled and run. Pin by digest, enforce signature verification (cosign/Kyverno/admission).')
print('PASS' if not vuln else 'VULNERABLE (see images above)')
sys.exit(2 if vuln else 0)

CO-cluster-secrets-exposure.script:
#!/usr/bin/env python3
# CO-cluster-secrets-exposure: detect secret-looking values stored in plaintext env vars
# or ConfigMaps (base64 is NOT encryption). READ-ONLY; reports location, never prints the value.
import sys, json, re, base64

SAMPLE = {"items":[
  {"kind":"ConfigMap","metadata":{"name":"app-config","namespace":"prod"},
   "data":{"LOG_LEVEL":"info","DB_PASSWORD":"FAKE-PASSWORD-123","api_token":"FAKE-TOKEN"}},
  {"kind":"Pod","metadata":{"name":"api","namespace":"prod"},
   "spec":{"containers":[{"name":"c","env":[{"name":"AWS_SECRET_ACCESS_KEY","value":"FAKE-SECRET"},{"name":"PORT","value":"8080"}]}]}}
]}

SECRET_KEY = re.compile(r'(pass|pwd|secret|token|api[_-]?key|private[_-]?key|cred)', re.I)

def load():
    if not sys.stdin.isatty():
        raw = sys.stdin.read().strip()
        if raw:
            try: return json.loads(raw)
            except json.JSONDecodeError: pass
    if len(sys.argv) > 1:
        try: return json.load(open(sys.argv[1]))
        except (OSError, json.JSONDecodeError): pass
    return SAMPLE

d = load()
items = d.get('items', [d]) if isinstance(d, dict) else [d]
vuln = False
print('=== cluster secret-exposure scan ===')
for it in items:
    kind = it.get('kind','?'); md = it.get('metadata', {}) or {}
    name = md.get('name','?'); ns = md.get('namespace','?')
    # ConfigMap plaintext secret keys
    for k in (it.get('data', {}) or {}):
        if SECRET_KEY.search(k):
            vuln = True
            print(f'  {kind} {ns}/{name}: key "{k}" looks secret-shaped but lives in a ConfigMap (NOT a Secret, not encrypted).')
    # env literal values (not valueFrom secretKeyRef)
    for c in (it.get('spec', {}) or {}).get('containers', []) or []:
        for e in c.get('env', []) or []:
            if SECRET_KEY.search(e.get('name','')) and 'value' in e and 'valueFrom' not in e:
                vuln = True
                print(f'  {kind} {ns}/{name}: env "{e["name"]}" set as an inline literal value (should be valueFrom.secretKeyRef + encryption-at-rest).')
if vuln:
    print('VULNERABLE: secret-shaped values stored in ConfigMaps/inline env -> readable by anyone with get on the object. Move to Secrets w/ KMS encryption-at-rest, mount via secretKeyRef, restrict RBAC.')
else:
    print('PASS: no plaintext secret-shaped values in ConfigMaps or inline env.')
sys.exit(2 if vuln else 0)

CO-admission-policy-bypass.script:
#!/usr/bin/env python3
# CO-admission-policy-bypass: flag admission policies running in audit/warn-only mode,
# webhooks with failurePolicy=Ignore, or broad namespace exemptions -> enforcement bypass. READ-ONLY.
import sys, json

SAMPLE = {"items":[
  {"kind":"ClusterPolicy","metadata":{"name":"require-nonroot"},
   "spec":{"validationFailureAction":"Audit"}},
  {"kind":"ValidatingWebhookConfiguration","metadata":{"name":"gatekeeper-validating"},
   "webhooks":[{"name":"validation.gatekeeper.sh","failurePolicy":"Ignore",
     "namespaceSelector":{"matchExpressions":[{"key":"control-plane","operator":"DoesNotExist"}]}}]}
]}

def load():
    if not sys.stdin.isatty():
        raw = sys.stdin.read().strip()
        if raw:
            try: return json.loads(raw)
            except json.JSONDecodeError: pass
    if len(sys.argv) > 1:
        try: return json.load(open(sys.argv[1]))
        except (OSError, json.JSONDecodeError): pass
    return SAMPLE

d = load()
items = d.get('items', [d]) if isinstance(d, dict) else [d]
vuln = False
print('=== admission-policy enforcement audit ===')
for it in items:
    kind = it.get('kind','?'); name = (it.get('metadata',{}) or {}).get('name','?')
    spec = it.get('spec', {}) or {}
    # Kyverno: validationFailureAction Audit/warn == not enforced
    vfa = spec.get('validationFailureAction') or spec.get('validationFailureActionOverrides')
    if vfa and str(vfa).lower() in ('audit','warn'):
        vuln = True
        print(f'  {kind}/{name}: validationFailureAction={vfa} -> AUDIT ONLY, violations are logged not blocked.')
    # Webhooks: failurePolicy Ignore == fail-open
    for w in it.get('webhooks', []) or []:
        if (w.get('failurePolicy') or '').lower() == 'ignore':
            vuln = True
            print(f'  {kind}/{name} webhook {w.get("name")}: failurePolicy=Ignore -> fail-open, admission bypassed when webhook is down.')
if vuln:
    print('VULNERABLE: admission control is audit-only or fail-open -> non-compliant/malicious workloads admitted. Set validationFailureAction=Enforce and failurePolicy=Fail.')
else:
    print('PASS: admission policies enforce (block) and webhooks fail-closed.')
sys.exit(2 if vuln else 0)

CO-tls-cert-provenance-ct-blindspot.script:
#!/usr/bin/env python3
# CO-tls-cert-provenance-ct-blindspot: query Certificate Transparency for certs issued on an OWNED domain.
# Surfaces unexpected/unknown issuers and the CT visibility a defender relies on. READ-ONLY passive.
import sys, json, urllib.request, urllib.error

DOMAIN = sys.argv[1] if len(sys.argv) > 1 else 'example.test'
KNOWN_ISSUERS = {'Lets Encrypt', "Let's Encrypt", 'DigiCert', 'Google Trust Services', 'Amazon'}

def ct_query(domain):
    url = f'https://crt.sh/?q=%25.{domain}&output=json'
    try:
        req = urllib.request.Request(url, headers={'User-Agent': 'ct-audit-readonly'})
        with urllib.request.urlopen(req, timeout=8) as r:
            return json.loads(r.read().decode(errors='replace') or '[]')
    except (urllib.error.URLError, json.JSONDecodeError, OSError):
        # DEFANGED offline sample: includes one unexpected issuer
        return [
            {'issuer_name': 'C=US, O=Let\'s Encrypt, CN=R3', 'name_value': f'www.{domain}'},
            {'issuer_name': 'C=XX, O=FAKE-UNKNOWN-CA, CN=rogue', 'name_value': f'vpn.{domain}'},
        ]

certs = ct_query(DOMAIN)
print(f'=== CT provenance check [{DOMAIN}] ===  ({len(certs)} cert records)')
unknown = []
for c in certs:
    iss = c.get('issuer_name', '')
    if not any(k in iss for k in KNOWN_ISSUERS):
        unknown.append((iss, c.get('name_value','')))
for iss, nv in unknown[:20]:
    print(f'  UNKNOWN issuer: {iss} for {nv}')
if unknown:
    print('VULNERABLE: certificate(s) for this domain issued by an issuer NOT on the expected list -> possible mis-issuance / rogue cert, AND it proves every cert is publicly logged in CT (a red-team cert leaves a permanent trace; a defender can monitor CT for surprise certs). Pin expected CAs, add CT monitoring + CAA records.')
    sys.exit(2)
print('PASS: all CT-logged certs are from expected issuers (and CT coverage confirms visibility).')

