#!/usr/bin/env python3
# CO-sockpuppet-account-aging: score OWNED test/persona accounts against the SAME aging/trust signals
# a platform defender uses to detect synthetic accounts (age, post history, contacts, verification).
# READ-ONLY: scores metadata you already hold; no account creation, no platform calls.
import sys, json, datetime

SAMPLE = {"accounts":[
  {"handle":"persona_a","created":"2026-06-20","posts":1,"connections":2,"email_verified":False,"phone_verified":False,"avatar":False},
  {"handle":"persona_b","created":"2023-01-05","posts":480,"connections":210,"email_verified":True,"phone_verified":True,"avatar":True}
]}

def load():
    if len(sys.argv) > 1:
        try: return json.load(open(sys.argv[1]))
        except (OSError, json.JSONDecodeError): pass
    return SAMPLE

d = load()
today = datetime.date.today()
vuln = False
print('=== sockpuppet account-aging signal audit ===')
for a in d.get('accounts', []):
    try:
        created = datetime.date.fromisoformat(a.get('created','1970-01-01'))
    except ValueError:
        created = today
    age = (today - created).days
    score = 0
    reasons = []
    if age < 90: score += 2; reasons.append(f'age={age}d (<90)')
    if a.get('posts',0) < 10: score += 1; reasons.append('low post history')
    if a.get('connections',0) < 10: score += 1; reasons.append('few connections')
    if not a.get('email_verified'): score += 1; reasons.append('email unverified')
    if not a.get('phone_verified'): score += 1; reasons.append('phone unverified')
    if not a.get('avatar'): score += 1; reasons.append('no avatar')
    print(f'  {a.get("handle")}: risk_score={score} ({", ".join(reasons) or "none"})')
    if score >= 3:
        vuln = True
        print('    VULNERABLE: account trips the synthetic-account heuristics a platform uses (young + sparse + unverified) -> likely auto-flagged/limited. As a defender, alert on this profile; as an operator, this persona is not credibly aged.')
print('PASS' if not vuln else 'VULNERABLE (see accounts above)')
sys.exit(2 if vuln else 0)
